// test_gitignore.cpp - Unit tests for gitignore pattern matching
// Tests git_ignore_matches() and underlying fnmatch_git() behavior

#include "test_harness.h"

// ============================================================================
// Helper: Create GitIgnoreList with a single pattern
// ============================================================================

static void setup_single_pattern(GitIgnoreList* list, const char* pattern,
                                  bool negated = false, bool anchored = false,
                                  bool is_directory = false) {
    git_ignore_init(list);

    // Ensure capacity
    if (list->capacity == 0) {
        list->capacity = 16;
        list->patterns = new GitIgnorePattern[list->capacity];
    }

    // Add a pattern (simulating what git_ignore_load does)
    if (list->count < list->capacity) {
        GitIgnorePattern* p = &list->patterns[list->count++];
        strncpy_s(p->pattern, pattern, sizeof(p->pattern) - 1);
        p->is_negation = negated;
        p->is_anchored = anchored;
        p->is_directory = is_directory;
        p->base_path[0] = '\0';
    }
}

// ============================================================================
// Exact Match Tests
// ============================================================================

TEST(gitignore_exact_match) {
    GitIgnoreList list;
    setup_single_pattern(&list, "foo.txt");

    TEST_ASSERT_TRUE(git_ignore_matches(&list, "foo.txt", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "bar.txt", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "foo.txt.bak", false));

    git_ignore_free(&list);
}

TEST(gitignore_exact_match_in_subdir) {
    GitIgnoreList list;
    setup_single_pattern(&list, "foo.txt");

    // Non-anchored pattern should match in subdirectories
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "subdir/foo.txt", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "a/b/c/foo.txt", false));

    git_ignore_free(&list);
}

// ============================================================================
// Star (*) Wildcard Tests
// ============================================================================

TEST(gitignore_star_extension) {
    GitIgnoreList list;
    setup_single_pattern(&list, "*.txt");

    TEST_ASSERT_TRUE(git_ignore_matches(&list, "foo.txt", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "bar.txt", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, ".txt", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "foo.c", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "txt", false));

    git_ignore_free(&list);
}

TEST(gitignore_star_prefix) {
    GitIgnoreList list;
    setup_single_pattern(&list, "test_*");

    TEST_ASSERT_TRUE(git_ignore_matches(&list, "test_foo", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "test_", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "test", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "my_test_foo", false));

    git_ignore_free(&list);
}

TEST(gitignore_star_middle) {
    GitIgnoreList list;
    setup_single_pattern(&list, "foo*bar");

    TEST_ASSERT_TRUE(git_ignore_matches(&list, "foobar", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "foo123bar", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "foo_bar", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "foobarbaz", false));

    git_ignore_free(&list);
}

TEST(gitignore_star_no_slash_crossing) {
    GitIgnoreList list;
    setup_single_pattern(&list, "*.txt");

    // In gitignore, non-anchored patterns match basenames in subdirectories
    // So *.txt matches file.txt in any directory
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "dir/file.txt", false));

    git_ignore_free(&list);
}

// ============================================================================
// Double Star (**) Tests
// ============================================================================

TEST(gitignore_doublestar_prefix) {
    GitIgnoreList list;
    setup_single_pattern(&list, "**/foo.txt");

    TEST_ASSERT_TRUE(git_ignore_matches(&list, "foo.txt", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "dir/foo.txt", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "a/b/c/foo.txt", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "foo.txt.bak", false));

    git_ignore_free(&list);
}

TEST(gitignore_doublestar_suffix) {
    GitIgnoreList list;
    setup_single_pattern(&list, "build/**");

    TEST_ASSERT_TRUE(git_ignore_matches(&list, "build/output.o", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "build/sub/file.txt", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "mybuild/file", false));

    git_ignore_free(&list);
}

TEST(gitignore_doublestar_middle) {
    GitIgnoreList list;
    setup_single_pattern(&list, "src/**/test.cpp");

    TEST_ASSERT_TRUE(git_ignore_matches(&list, "src/test.cpp", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "src/foo/test.cpp", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "src/a/b/c/test.cpp", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "lib/test.cpp", false));

    git_ignore_free(&list);
}

// ============================================================================
// Question Mark (?) Tests
// ============================================================================

TEST(gitignore_question_mark) {
    GitIgnoreList list;
    setup_single_pattern(&list, "file?.txt");

    TEST_ASSERT_TRUE(git_ignore_matches(&list, "file1.txt", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "fileA.txt", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "file.txt", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "file12.txt", false));

    git_ignore_free(&list);
}

TEST(gitignore_question_no_slash) {
    GitIgnoreList list;
    setup_single_pattern(&list, "a?b");

    TEST_ASSERT_TRUE(git_ignore_matches(&list, "aXb", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "a/b", false));  // ? shouldn't match /

    git_ignore_free(&list);
}

// ============================================================================
// Character Class ([]) Tests
// ============================================================================

TEST(gitignore_bracket_simple) {
    GitIgnoreList list;
    setup_single_pattern(&list, "[abc]");

    TEST_ASSERT_TRUE(git_ignore_matches(&list, "a", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "b", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "c", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "d", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "abc", false));

    git_ignore_free(&list);
}

TEST(gitignore_bracket_range) {
    GitIgnoreList list;
    setup_single_pattern(&list, "[a-z].txt");

    TEST_ASSERT_TRUE(git_ignore_matches(&list, "a.txt", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "m.txt", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "z.txt", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "A.txt", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "1.txt", false));

    git_ignore_free(&list);
}

TEST(gitignore_bracket_negation) {
    GitIgnoreList list;
    setup_single_pattern(&list, "[!abc]");

    TEST_ASSERT_FALSE(git_ignore_matches(&list, "a", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "b", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "c", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "d", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "x", false));

    git_ignore_free(&list);
}

TEST(gitignore_bracket_in_pattern) {
    GitIgnoreList list;
    setup_single_pattern(&list, "file[0-9].txt");

    TEST_ASSERT_TRUE(git_ignore_matches(&list, "file0.txt", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "file5.txt", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "file9.txt", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "fileA.txt", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "file10.txt", false));

    git_ignore_free(&list);
}

// ============================================================================
// Directory-only Pattern Tests
// ============================================================================

TEST(gitignore_directory_only) {
    GitIgnoreList list;
    setup_single_pattern(&list, "build", false, false, true);  // is_directory = true

    TEST_ASSERT_TRUE(git_ignore_matches(&list, "build", true));   // is_dir = true
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "build", false)); // is_dir = false (file)

    git_ignore_free(&list);
}

// ============================================================================
// Negation Pattern Tests
// ============================================================================

TEST(gitignore_negation) {
    GitIgnoreList list;
    git_ignore_init(&list);

    // Allocate pattern storage
    list.capacity = 16;
    list.patterns = new GitIgnorePattern[list.capacity];

    // First pattern: ignore all .txt
    {
        GitIgnorePattern* p = &list.patterns[list.count++];
        strncpy_s(p->pattern, "*.txt", sizeof(p->pattern) - 1);
        p->is_negation = false;
        p->is_anchored = false;
        p->is_directory = false;
        p->base_path[0] = '\0';
    }

    // Second pattern: but not important.txt
    {
        GitIgnorePattern* p = &list.patterns[list.count++];
        strncpy_s(p->pattern, "important.txt", sizeof(p->pattern) - 1);
        p->is_negation = true;
        p->is_anchored = false;
        p->is_directory = false;
        p->base_path[0] = '\0';
    }

    TEST_ASSERT_TRUE(git_ignore_matches(&list, "foo.txt", false));
    TEST_ASSERT_TRUE(git_ignore_matches(&list, "bar.txt", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "important.txt", false));  // Negated!

    git_ignore_free(&list);
}

// ============================================================================
// Edge Cases
// ============================================================================

TEST(gitignore_empty_pattern) {
    GitIgnoreList list;
    git_ignore_init(&list);
    // Empty list should match nothing
    TEST_ASSERT_FALSE(git_ignore_matches(&list, "anything", false));
    git_ignore_free(&list);
}

TEST(gitignore_null_inputs) {
    GitIgnoreList list;
    git_ignore_init(&list);

    TEST_ASSERT_FALSE(git_ignore_matches(nullptr, "path", false));
    TEST_ASSERT_FALSE(git_ignore_matches(&list, nullptr, false));
    TEST_ASSERT_FALSE(git_ignore_matches(nullptr, nullptr, false));

    git_ignore_free(&list);
}

TEST(gitignore_init_free) {
    GitIgnoreList list;
    git_ignore_init(&list);
    TEST_ASSERT_EQ(list.count, (size_t)0);
    git_ignore_free(&list);
    TEST_ASSERT_EQ(list.count, (size_t)0);
}
